query:
-- Buscar ID do Gabriel
SELECT id, name, email FROM users WHERE name LIKE '%Gabriel%' OR email LIKE '%gabriel%';

-- Buscar atividades do Gabriel
SELECT * FROM atividades_diarias WHERE corretorId IN (SELECT id FROM users WHERE name LIKE '%Gabriel%') ORDER BY createdAt DESC LIMIT 20;

-- Verificar pontuação total do Gabriel
SELECT corretorId, SUM(pontos) as total_pontos, COUNT(*) as total_atividades 
FROM atividades_diarias 
WHERE corretorId IN (SELECT id FROM users WHERE name LIKE '%Gabriel%')
GROUP BY corretorId;

